// AMD module for the mod_fastpix activity form .vtt captions dropzone.
// AMD-wrapped by hand since the dev environment lacks grunt amd.
// Replace via `grunt amd` once available. Mirrors amd/src/captions_upload.js.
//
// Per A2: posts ONLY to Moodle's own /repository/repository_ajax.php — never
// to the FastPix CDN.

define(['core/config', 'core/notification'], function(Config, Notification) {
    'use strict';

    var SELECTORS = {
        dropzone: '[data-region="fastpix-vtt-dropzone"]',
        input:    '[data-region="fastpix-vtt-input"]',
        browse:   '[data-action="fastpix-vtt-browse"]',
        status:   '[data-region="fastpix-vtt-status"]'
    };

    var cfg = {itemid: 0, repoId: 0, contextId: 0, strings: {}};

    var setStatus = function(dropzone, message, kind) {
        var el = dropzone.querySelector(SELECTORS.status);
        if (!el) { return; }
        el.hidden = !message;
        el.textContent = message || '';
        el.className = 'fastpix-vtt-status' + (kind ? ' fastpix-vtt-status--' + kind : '');
    };

    var uploadFile = function(dropzone, file) {
        if (!file) { return; }
        if (!/\.vtt$/i.test(file.name)) {
            setStatus(dropzone, cfg.strings.badtype, 'danger');
            return;
        }
        setStatus(dropzone, cfg.strings.uploading, 'muted');

        var formData = new FormData();
        formData.append('sesskey', Config.sesskey);
        formData.append('repo_id', cfg.repoId);
        formData.append('itemid', cfg.itemid);
        formData.append('ctx_id', cfg.contextId);
        formData.append('savepath', '/');
        formData.append('title', file.name);
        formData.append('overwrite', 1);
        formData.append('repo_upload_file', file);

        fetch(Config.wwwroot + '/repository/repository_ajax.php?action=upload', {
            method: 'POST',
            body: formData
        }).then(function(response) {
            return response.json();
        }).then(function(data) {
            if (!data || data.error || data.errorcode) {
                setStatus(dropzone, (data && data.error) || cfg.strings.uploaderror, 'danger');
                return;
            }
            dropzone.classList.add('has-file');
            setStatus(dropzone, data.file || file.name, 'success');
        }).catch(function(e) {
            Notification.exception(e);
            setStatus(dropzone, cfg.strings.uploaderror, 'danger');
        });
    };

    return {
        init: function(config) {
            cfg = config || cfg;
            var dropzone = document.querySelector(SELECTORS.dropzone);
            if (!dropzone) { return; }
            var input = dropzone.querySelector(SELECTORS.input);
            var browse = dropzone.querySelector(SELECTORS.browse);

            if (browse) {
                browse.addEventListener('click', function(e) {
                    e.preventDefault();
                    e.stopPropagation();
                    if (input) { input.click(); }
                });
            }

            dropzone.addEventListener('click', function(e) {
                if (e.target === browse || (browse && browse.contains(e.target))) { return; }
                if (input) { input.click(); }
            });

            dropzone.addEventListener('keydown', function(e) {
                if (e.key === 'Enter' || e.key === ' ') {
                    e.preventDefault();
                    if (input) { input.click(); }
                }
            });

            if (input) {
                input.addEventListener('change', function() {
                    var file = input.files && input.files[0];
                    if (file) { uploadFile(dropzone, file); }
                });
            }

            ['dragenter', 'dragover'].forEach(function(ev) {
                dropzone.addEventListener(ev, function(e) {
                    e.preventDefault();
                    e.stopPropagation();
                    dropzone.classList.add('is-dragging');
                });
            });
            ['dragleave', 'dragend'].forEach(function(ev) {
                dropzone.addEventListener(ev, function(e) {
                    e.preventDefault();
                    e.stopPropagation();
                    dropzone.classList.remove('is-dragging');
                });
            });
            dropzone.addEventListener('drop', function(e) {
                e.preventDefault();
                e.stopPropagation();
                dropzone.classList.remove('is-dragging');
                var file = e.dataTransfer && e.dataTransfer.files && e.dataTransfer.files[0];
                if (file) { uploadFile(dropzone, file); }
            });
        }
    };
});
